// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('text japanese', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('text japanese', async function() {
    // Test name: text japanese
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/department-goal | 
    await driver.get("http://localhost:4200/user/department-goal");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | assertText | css=.ant-layout-content > .ant-typography | 部門目標
    assert(await driver.findElement(By.css(".ant-layout-content > .ant-typography")).getText() == "部門目標");

    // 4 | assertText | css=.ant-form-item:nth-child(1) .ant-form-item-no-colon | 評価期間
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(1) .ant-form-item-no-colon")).getText() == "評価期間");

    // 5 | assertText | css=.ant-form-item:nth-child(2) .ant-form-item-no-colon | 部署
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(2) .ant-form-item-no-colon")).getText() == "部署");

    // 6 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(1) | 部門目標
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(1)")).getText() == "部門目標");

    // 7 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(2) | 指標・水準 (達成数値)
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).getText() == "指標・水準 (達成数値)");

    // 8 | assertText | css=.ant-table-thead .ant-table-cell:nth-child(3) | 手段・方法 (どのように)
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "手段・方法 (どのように)");
  });
});
